app.modals.ViewRecoveryCodesModal=function(){var e=abp.services.app.profile,o=null;this.init=function(t){var i=t.getModal();(o=i.find("form[name=AuthenticatorVerificationModalForm]")).validate(),i.find("#verifyButton").click((function(){if(o.valid()){var t=o.serializeFormToObject();t.code=$("#authenticatorCode").val(),e.viewRecoveryCodes(t).done((function(e){o.hide(),$("#recoveryCodesCard").show();let t='<div class="row">';e.recoveryCodes.forEach((e=>{t+=`<div class="text-dark fs-6 fw-bold col-6">${e}</div>`})),t+="</div>\n            </div>",$("#recoveryCodes").html(t);const i=e.recoveryCodes.join("\r\n");$("#btnDownload").on("click",(()=>{const e=document.createElement("a");e.setAttribute("href","data:text/plain;charset=utf-8,"+encodeURIComponent(i)),e.setAttribute("download","recovery-codes.txt"),e.click(),URL.revokeObjectURL(e.href)})),$("#btnCopy").on("click",(()=>{navigator.clipboard.writeText(i)}))})).always((function(e){$("#authenticatorCode").val("")}))}}))}};